import { supabase } from './supabase';
export default {
  async get() {
    const {
      data,
      error
    } = await supabase.from('quote_settings').select('*').maybeSingle();
    if (error) throw error;
    if (!data) {
      const {
        data: newData,
        error: createError
      } = await supabase.from('quote_settings').insert({
        validity_hours: 48
      }).select().single();
      if (createError) throw createError;
      return newData;
    }
    return data;
  },
  async update(id, updates) {
    const {
      data,
      error
    } = await supabase.from('quote_settings').update({
      ...updates,
      updated_at: new Date().toISOString()
    }).eq('id', id).select().single();
    if (error) throw error;
    return data;
  }
};
